class Solution:
    def findKthNumber(self, n: int, k: int) -> int:
        left, right = 1, n
        while left <= right:
            mid = (left + right) // 2
            count = self.countSmaller(mid, n)
            if count < k:
                left = mid + 1
            else:
                right = mid - 1
        return left

    def countSmaller(self, threshold: int, n: int) -> int:
        count = 0
        for i in range(1, n + 1):
            if i < threshold:
                count += 1
        return count
```
